insert into recipes (id, name, source, visibility, prep_time_min, preparation, objective, needs_review) values ('f1b0f649-a281-4dfa-a0a1-e938bfdb5e96', 'Omelete Proteico com tomate', 'admin', 'public', 25, 'Bata os ovos em um recipiente. Refogue cebola e tomate em uma frigideira antiaderente com pouco azeite. Adicione o frango desfiado e depois os ovos. Cozinhe em fogo baixo até firmar e dobre ao meio. Adicione tomate durante o preparo para aumentar fibras e volume alimentar. Finalize ajustando os temperos naturais e sirva ainda quente.', 'Promover saciedade, praticidade, controle calórico moderado e aderência alimentar.', false);
