insert into recipes (id, name, source, visibility, prep_time_min, preparation, objective, needs_review) values ('c811f263-d146-4e9f-9e08-6267b41477a3', 'Omelete Proteico com abobrinha', 'admin', 'public', 22, 'Bata os ovos em um recipiente. Refogue cebola e tomate em uma frigideira antiaderente com pouco azeite. Adicione o frango desfiado e depois os ovos. Cozinhe em fogo baixo até firmar e dobre ao meio. Adicione abobrinha durante o preparo para aumentar fibras e volume alimentar. Finalize ajustando os temperos naturais e sirva ainda quente.', 'Promover saciedade, praticidade, controle calórico moderado e aderência alimentar.', false);
