insert into recipes (id, name, source, visibility, prep_time_min, preparation, objective, needs_review) values ('a60c66b6-ab3e-4d3e-8626-28e6468e2d1a', 'Omelete Proteico com brócolis', 'admin', 'public', 11, 'Bata os ovos em um recipiente. Refogue cebola e tomate em uma frigideira antiaderente com pouco azeite. Adicione o frango desfiado e depois os ovos. Cozinhe em fogo baixo até firmar e dobre ao meio. Adicione brócolis durante o preparo para aumentar fibras e volume alimentar. Finalize ajustando os temperos naturais e sirva ainda quente.', 'Promover saciedade, praticidade, controle calórico moderado e aderência alimentar.', false);
