insert into recipes (id, name, source, visibility, prep_time_min, preparation, objective, needs_review) values ('f3d1bd15-d5d1-48ff-ba03-cd72fd221c04', 'Omelete Proteico com brócolis', 'admin', 'public', 22, 'Bata os ovos em um recipiente. Refogue cebola e tomate em uma frigideira antiaderente com pouco azeite. Adicione o frango desfiado e depois os ovos. Cozinhe em fogo baixo até firmar e dobre ao meio. Adicione brócolis durante o preparo para aumentar fibras e volume alimentar. Finalize ajustando os temperos naturais e sirva ainda quente.', 'Promover saciedade, praticidade, controle calórico moderado e aderência alimentar.', false);
